{
  "name": "DukaanMitra Mobile App",
  "description": "A high-fidelity PWA for the DukaanMitra Kirana ledger system, featuring real-time AI parsing and vision-based billing.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { generateAssistantResponse } from '../services/geminiService';

const ChatBot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'bot'; text: string }[]>([
    { role: 'bot', text: "Hello! I'm the Platform Assistant. Ask me anything about scaling DukaanMitra or technical architecture." }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Live API Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const sessionRef = useRef<any>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;
    const userText = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userText }]);
    setIsTyping(true);

    const response = await generateAssistantResponse(userText, messages);
    setMessages(prev => [...prev, { role: 'bot', text: response }]);
    setIsTyping(false);
  };

  const decode = (base64: string) => {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  };

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  };

  const decodeAudioData = async (
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
  ): Promise<AudioBuffer> => {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  };

  const toggleLiveMode = async () => {
    if (isLiveMode) {
      // Close session
      if (sessionRef.current) {
        sessionRef.current.close();
      }
      setIsLiveMode(false);
      return;
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
            console.log('Live session opened');
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const base64 = encode(new Uint8Array(int16.buffer));

              sessionPromise.then((session) => {
                session.sendRealtimeInput({
                  media: { data: base64, mimeType: 'audio/pcm;rate=16000' }
                });
              });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
            setIsLiveMode(true);
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData && outputCtx) {
              const audioBuffer = await decodeAudioData(decode(audioData), outputCtx, 24000, 1);
              const source = outputCtx.createBufferSource();
              source.buffer = audioBuffer;
              source.connect(outputCtx.destination);

              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += audioBuffer.duration;
              sourcesRef.current.add(source);
              source.onended = () => sourcesRef.current.delete(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
            }
          },
          onerror: (e) => console.error('Live Error:', e),
          onclose: () => setIsLiveMode(false)
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction: 'You are a technical assistant for the DukaanMitra platform. You speak concisely and use Hinglish when helpful. You help shop owners understand their platform data.'
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error('Failed to start Live API:', err);
    }
  };

  return (
    <>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`fixed bottom-8 right-8 w-16 h-16 rounded-full shadow-2xl flex items-center justify-center text-3xl transition-all duration-300 z-50 ${
          isOpen ? 'bg-rose-500 rotate-90 scale-90' : 'bg-indigo-600 hover:bg-indigo-700 hover:scale-110'
        }`}
      >
        {isOpen ? '✕' : '🤖'}
      </button>

      <div className={`fixed bottom-28 right-8 w-[400px] h-[600px] bg-white rounded-[2.5rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] border border-slate-200 flex flex-col overflow-hidden transition-all duration-300 z-50 transform origin-bottom-right ${
        isOpen ? 'scale-100 opacity-100' : 'scale-0 opacity-0 pointer-events-none'
      }`}>
        <div className="bg-slate-900 p-6 text-white flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center text-xl shadow-lg">🧠</div>
            <div>
              <h3 className="font-bold text-sm tracking-tight">Platform Brain</h3>
              <div className="flex items-center space-x-1.5 mt-0.5">
                <span className={`w-1.5 h-1.5 rounded-full ${isLiveMode ? 'bg-emerald-500 animate-ping' : 'bg-emerald-500 animate-pulse'}`}></span>
                <span className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{isLiveMode ? 'Live Voice Active' : 'Gemini 3 Pro'}</span>
              </div>
            </div>
          </div>
          <button 
            onClick={toggleLiveMode}
            className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${
              isLiveMode ? 'bg-rose-500 text-white animate-pulse' : 'bg-white/10 text-white hover:bg-white/20'
            }`}
          >
            {isLiveMode ? '🛑' : '🎙️'}
          </button>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 bg-slate-50/50">
          {isLiveMode ? (
            <div className="h-full flex flex-col items-center justify-center space-y-6">
              <div className="flex items-center space-x-3">
                {[...Array(5)].map((_, i) => (
                  <div 
                    key={i} 
                    className="w-2 h-12 bg-indigo-500 rounded-full animate-wave" 
                    style={{ animationDelay: `${i * 0.1}s` }}
                  />
                ))}
              </div>
              <p className="text-slate-500 font-black uppercase tracking-widest text-xs animate-pulse">Assistant is listening...</p>
              <button 
                onClick={toggleLiveMode}
                className="px-6 py-2 bg-rose-100 text-rose-600 rounded-full text-xs font-bold uppercase"
              >
                End Voice Session
              </button>
            </div>
          ) : (
            <>
              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] p-4 rounded-3xl text-sm leading-relaxed ${
                    m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 shadow-sm border border-slate-100 rounded-tl-none'
                  }`}>
                    {m.text}
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="flex justify-start">
                  <div className="bg-white p-4 rounded-2xl flex space-x-1 shadow-sm border border-slate-100">
                    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce delay-75"></div>
                    <div className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce delay-150"></div>
                  </div>
                </div>
              )}
            </>
          )}
        </div>

        {!isLiveMode && (
          <div className="p-4 bg-white border-t border-slate-100">
            <div className="flex items-center space-x-2 bg-slate-100 rounded-2xl p-2 px-4">
              <input
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyPress={e => e.key === 'Enter' && handleSend()}
                placeholder="Ask about Supabase, Scaling..."
                className="flex-1 bg-transparent border-none focus:outline-none text-sm py-2"
              />
              <button onClick={handleSend} className="w-8 h-8 rounded-xl bg-indigo-600 text-white flex items-center justify-center disabled:opacity-30">
                ➔
              </button>
            </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes wave {
          0%, 100% { height: 12px; }
          50% { height: 48px; }
        }
        .animate-wave {
          animation: wave 1s ease-in-out infinite;
        }
      `}</style>
    </>
  );
};

export default ChatBot;

import React, { useState, useRef, useEffect } from 'react';
import { parseMessage, parseImageBill, getSmartSuggestions } from '../services/geminiService';
import { Customer, Transaction, SystemLog } from '../types';

interface SimulatorProps {
  customers: Customer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  logs: SystemLog[];
  setLogs: React.Dispatch<React.SetStateAction<SystemLog[]>>;
}

const Simulator: React.FC<SimulatorProps> = ({ 
  customers, setCustomers, 
  transactions, setTransactions, 
  setLogs 
}) => {
  const [message, setMessage] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeRoute, setActiveRoute] = useState<string | null>(null);
  const [costSaved, setCostSaved] = useState(0);
  const [aiRequests, setAiRequests] = useState(0);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [chatHistory, setChatHistory] = useState<{ sender: 'user' | 'bot'; text: string; isImage?: boolean; imageData?: string }[]>([
    { sender: 'bot', text: "Namaste! DukaanMitra AI Ledger Online. 🧠\nTry 'Rahul 500 udhaar' or 'Rahul ka hisaab batao'." }
  ]);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chatHistory, isProcessing]);

  useEffect(() => {
    const fetchSuggestions = async () => {
      if (transactions.length > 0) {
        const hints = await getSmartSuggestions(transactions);
        setSuggestions(hints);
      }
    };
    fetchSuggestions();
  }, [transactions]);

  const handleSendMessage = async (customMsg?: string) => {
    const userMsg = (customMsg || message).trim();
    if (!userMsg || isProcessing) return;

    setMessage("");
    setChatHistory(prev => [...prev, { sender: 'user', text: userMsg }]);
    setIsProcessing(true);
    setActiveRoute("WEBHOOK_INGRESS");

    // Simulation logic
    setTimeout(async () => {
      const lowerMsg = userMsg.toLowerCase();
      const garbageKeywords = ['ok', 'thanks', 'bye', 'theek', 'shukriya'];
      const isGarbage = garbageKeywords.some(kw => lowerMsg.includes(kw)) || userMsg.length <= 2;

      if (isGarbage) {
        setActiveRoute("CHAI_SUTTA_FILTER");
        setCostSaved(prev => prev + 1);
        await new Promise(r => setTimeout(r, 1000));
        setChatHistory(prev => [...prev, { sender: 'bot', text: "☕ Filter: Ignoring courtesy message to save AI tokens." }]);
        setIsProcessing(false);
        setActiveRoute(null);
        return;
      }

      setActiveRoute("GEMINI_PARSING");
      setAiRequests(prev => prev + 1);

      const result = await parseMessage(userMsg);

      if (result.action === 'add_entry') {
        setActiveRoute("SHEETS_SETTLEMENT");
        const newTrans: Transaction = {
          transId: `TX-${Date.now()}`,
          storeId: "DM-001",
          phone: "919000000000",
          customerName: result.customer_name || "Unknown",
          amount: result.amount || 0,
          items: result.item || "Misc",
          date: new Date().toISOString()
        };
        setTransactions(prev => [...prev, newTrans]);
        setCustomers(prev => prev.map(c => 
          c.phone === "919000000000" ? { ...c, totalLTV: c.totalLTV + (newTrans.amount || 0) } : c
        ));
      } else if (result.action === 'get_summary') {
        setActiveRoute("SHEETS_SETTLEMENT");
        const name = result.customer_name?.toLowerCase();
        const relatedTrans = transactions.filter(t => t.customerName.toLowerCase().includes(name || ''));
        const total = relatedTrans.reduce((sum, t) => sum + t.amount, 0);

        result.user_message = `Sir, ${result.customer_name} ka total udhaar ₹${total} hai. Pichli entry ₹${relatedTrans[0]?.amount || 0} ki thi.`;
      }

      setChatHistory(prev => [...prev, { sender: 'bot', text: result.user_message }]);
      setIsProcessing(false);
      setTimeout(() => setActiveRoute(null), 1000);
    }, 500);
  };

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const fullDataUrl = reader.result as string;
        const base64 = fullDataUrl.split(',')[1];

        setChatHistory(prev => [...prev, { sender: 'user', text: "Parsing bill photo...", isImage: true, imageData: fullDataUrl }]);
        setIsProcessing(true);
        setActiveRoute("VISION_ENGINE");
        setAiRequests(prev => prev + 1);

        const result = await parseImageBill(base64);

        if (result.action === 'add_bulk_entries' && result.items) {
          setActiveRoute("SHEETS_SETTLEMENT");
          const bulk = result.items.map((it, i) => ({
            transId: `TX-V-${Date.now()}-${i}`,
            storeId: "DM-001",
            phone: "919000000000",
            customerName: result.customer_name || "Vision Customer",
            amount: it.amount,
            items: it.item,
            date: new Date().toISOString()
          }));
          setTransactions(prev => [...prev, ...bulk]);
        }

        setChatHistory(prev => [...prev, { sender: 'bot', text: result.user_message }]);
        setIsProcessing(false);
        setTimeout(() => setActiveRoute(null), 1000);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-160px)]">
      {/* WhatsApp Device Simulator */}
      <div className="lg:w-[400px] mx-auto bg-slate-900 p-3 rounded-[3rem] shadow-2xl flex flex-col relative border-[8px] border-slate-800">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-40 h-6 bg-slate-800 rounded-b-2xl z-10"></div>

        <div className="flex-1 bg-[#efe7de] rounded-[2.5rem] overflow-hidden flex flex-col relative">
          {/* WA Header */}
          <div className="bg-indigo-700 p-4 pt-8 text-white flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 bg-indigo-500 rounded-full flex items-center justify-center font-bold">DM</div>
              <div>
                <p className="font-bold text-sm">DukaanMitra AI</p>
                <p className="text-[10px] opacity-70">Desi Assistant Online</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[8px] opacity-50 uppercase font-black">Cost Saved</p>
              <p className="text-xs font-bold text-emerald-400">₹{costSaved * 5}</p>
            </div>
          </div>

          {/* Chat Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar">
            {chatHistory.map((chat, i) => (
              <div key={i} className={`flex ${chat.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm ${
                  chat.sender === 'user' ? 'bg-[#dcf8c6] rounded-tr-none' : 'bg-white rounded-tl-none border-l-4 border-l-indigo-500'
                }`}>
                  {chat.isImage && <img src={chat.imageData} className="rounded-lg mb-2 max-h-48 w-full object-cover" />}
                  <p className="whitespace-pre-wrap">{chat.text}</p>
                  <p className="text-[8px] text-slate-400 mt-1 text-right">Delivered</p>
                </div>
              </div>
            ))}
            {isProcessing && (
              <div className="flex justify-start">
                <div className="bg-white/80 backdrop-blur-sm p-2 rounded-xl flex items-center space-x-2">
                  <div className="flex space-x-1">
                    <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce delay-75"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce delay-150"></div>
                  </div>
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-3 bg-white border-t space-y-2">
            <div className="flex items-center space-x-2 overflow-x-auto no-scrollbar py-1">
              {suggestions.map((s, i) => (
                <button key={i} onClick={() => handleSendMessage(s)} className="shrink-0 px-3 py-1 bg-slate-100 rounded-full text-[10px] font-bold text-slate-600 border border-slate-200">
                  {s}
                </button>
              ))}
            </div>
            <div className="flex items-center space-x-2">
              <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
              <button onClick={() => fileInputRef.current?.click()} className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center">📷</button>
              <input 
                value={message}
                onChange={e => setMessage(e.target.value)}
                onKeyPress={e => e.key === 'Enter' && handleSendMessage()}
                placeholder="Type 'Rahul 500'..."
                className="flex-1 bg-slate-100 rounded-full px-4 py-2 text-sm focus:outline-none"
              />
              <button onClick={() => handleSendMessage()} className="w-10 h-10 rounded-full bg-indigo-600 text-white flex items-center justify-center">➔</button>
            </div>
          </div>
        </div>
      </div>

      {/* Backend Orchestrator Tracing Panel */}
      <div className="flex-1 space-y-6 hidden lg:block">
        <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm h-full flex flex-col">
          <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2 italic uppercase">
            <span className="text-indigo-600">⚡</span> Live Orchestrator Trace
          </h3>

          <div className="space-y-4 flex-1">
            {[
              { id: 'WEBHOOK_INGRESS', label: 'Webhook Ingress', icon: '🔌' },
              { id: 'CHAI_SUTTA_FILTER', label: 'Chai-Sutta Filter', icon: '☕' },
              { id: 'GEMINI_PARSING', label: 'Gemini 3 Flash Parse', icon: '🧠' },
              { id: 'VISION_ENGINE', label: 'Vision Pipeline', icon: '📸' },
              { id: 'SHEETS_SETTLEMENT', label: 'Sheets Settlement', icon: '📑' }
            ].map((route) => (
              <div key={route.id} className={`p-4 rounded-2xl border transition-all duration-500 flex items-center gap-4 ${
                activeRoute === route.id ? 'bg-indigo-600 border-indigo-400 text-white scale-[1.03] shadow-lg' : 'bg-slate-50 border-slate-100 opacity-40'
              }`}>
                <span className="text-2xl">{route.icon}</span>
                <div className="flex-1">
                  <p className="text-[10px] font-black uppercase tracking-widest">{route.label}</p>
                  <p className="text-xs opacity-70 italic">{activeRoute === route.id ? 'ACTIVE PROCESSING...' : 'STANDBY'}</p>
                </div>
                {activeRoute === route.id && <div className="w-2 h-2 rounded-full bg-white animate-ping"></div>}
              </div>
            ))}
          </div>

          <div className="mt-8 bg-slate-900 text-white p-6 rounded-3xl">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-[8px] font-black text-indigo-400 uppercase">AI Requests</p>
                <p className="text-2xl font-black">{aiRequests}</p>
              </div>
              <div>
                <p className="text-[8px] font-black text-emerald-400 uppercase">Cache Savings</p>
                <p className="text-2xl font-black">₹{costSaved * 5}</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Simulator;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import TransactionList from './components/TransactionList';
import Simulator from './components/Simulator';
import ShopPanel from './components/ShopPanel';
import SuperAdmin from './components/SuperAdmin';
import SystemLogs from './components/SystemLogs';
import DeploymentGuide from './components/DeploymentGuide';
import OperationsPlaybook from './components/OperationsPlaybook';
import ReliabilityPlaybook from './components/ReliabilityPlaybook';
import ScalingPlaybook from './components/ScalingPlaybook';
import PlatformSaaS from './components/PlatformSaaS';
import FounderOperations from './components/FounderOperations';
import StreetSalesPlaybook from './components/StreetSalesPlaybook';
import AssetLibrary from './components/AssetLibrary';
import BuildGuide from './components/BuildGuide';
import RecoveryOps from './components/RecoveryOps';
import OptimizationPlaybook from './components/OptimizationPlaybook';
import ArchitectureGuide from './components/ArchitectureGuide';
import SheetsDatabase from './components/SheetsDatabase';
import ChatBot from './components/ChatBot';
import { INITIAL_CUSTOMERS, INITIAL_TRANSACTIONS, INITIAL_LOGS } from './constants';
import { Customer, Transaction, SystemLog, View } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('landing');

  // Persistence Loading
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('dm_customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('dm_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [logs, setLogs] = useState<SystemLog[]>(INITIAL_LOGS);

  // Persistence Saving
  useEffect(() => {
    localStorage.setItem('dm_customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('dm_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const renderView = () => {
    switch (activeView) {
      case 'landing':
        return <LandingPage setView={setActiveView} />;
      case 'superadmin':
        return <SuperAdmin customers={customers} transactions={transactions} logs={logs} />;
      case 'shop_panel':
        return (
          <ShopPanel 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'dashboard':
        return <Dashboard customers={customers} transactions={transactions} />;
      case 'sheets_db':
        return <SheetsDatabase customers={customers} transactions={transactions} />;
      case 'architecture':
        return <ArchitectureGuide />;
      case 'build':
        return <BuildGuide />;
      case 'optimization':
        return <OptimizationPlaybook />;
      case 'recovery':
        return <RecoveryOps />;
      case 'assets':
        return <AssetLibrary />;
      case 'sales':
        return <StreetSalesPlaybook />;
      case 'founder':
        return <FounderOperations customers={customers} />;
      case 'platform':
        return <PlatformSaaS />;
      case 'scaling':
        return <ScalingPlaybook />;
      case 'customers':
        return <CustomerList customers={customers} transactions={transactions} />;
      case 'transactions':
        return <TransactionList transactions={transactions} />;
      case 'deployment':
        return <DeploymentGuide />;
      case 'operations':
        return <OperationsPlaybook />;
      case 'reliability':
        return <ReliabilityPlaybook />;
      case 'simulator':
        return (
          <Simulator 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'logs':
        return <SystemLogs logs={logs} />;
      default:
        return <Dashboard customers={customers} transactions={transactions} />;
    }
  };

  return (
    <Layout activeView={activeView} setView={setActiveView}>
      {renderView()}
      {activeView !== 'landing' && <ChatBot />}
    </Layout>
  );
};

