export const getNearbyLogistics = async (lat: number, lng: number): Promise<{ text: string, links: { uri: string, title: string }[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  const query = "Find wholesale kirana suppliers, distributors, and logistics partners nearby.";

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: [{ parts: [{ text: query }] }],
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: {
              latitude: lat,
              longitude: lng
            }
          }
        }
      },
    });

    const text = response.text || "No data found.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        uri: c.maps.uri,
        title: c.maps.title
      }));

    return { text, links };
  } catch (error) {
    console.error("Maps Grounding Error:", error);
    return { text: "Error fetching nearby logistics data.", links: [] };
  }
};

