import React, { useState, useEffect } from 'react';
import { onAuthStateChanged, User } from 'firebase/auth';
import { auth } from './firebase';
import Layout from './components/Layout';
import LandingPage from './components/LandingPage';
import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import TransactionList from './components/TransactionList';
import Simulator from './components/Simulator';
import ShopPanel from './components/ShopPanel';
import SuperAdmin from './components/SuperAdmin';
import SystemLogs from './components/SystemLogs';
import DeploymentGuide from './components/DeploymentGuide';
import OperationsPlaybook from './components/OperationsPlaybook';
import ReliabilityPlaybook from './components/ReliabilityPlaybook';
import ScalingPlaybook from './components/ScalingPlaybook';
import PlatformSaaS from './components/PlatformSaaS';
import FounderOperations from './components/FounderOperations';
import StreetSalesPlaybook from './components/StreetSalesPlaybook';
import AssetLibrary from './components/AssetLibrary';
import BuildGuide from './components/BuildGuide';
import RecoveryOps from './components/RecoveryOps';
import OptimizationPlaybook from './components/OptimizationPlaybook';
import ArchitectureGuide from './components/ArchitectureGuide';
import SheetsDatabase from './components/SheetsDatabase';
import ChatBot from './components/ChatBot';
import Auth from './components/Auth';
import { INITIAL_CUSTOMERS, INITIAL_TRANSACTIONS, INITIAL_LOGS } from './constants';
import { Customer, Transaction, SystemLog, View } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('landing');
  const [user, setUser] = useState<User | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  // Persistence Loading
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('dm_customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('dm_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [logs, setLogs] = useState<SystemLog[]>(INITIAL_LOGS);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setAuthLoading(false);

      // If user logs in and we are on landing, redirect to dashboard
      if (currentUser && activeView === 'landing') {
        setActiveView('dashboard');
      }
    });
    return () => unsubscribe();
  }, [activeView]);

  // Persistence Saving
  useEffect(() => {
    localStorage.setItem('dm_customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('dm_transactions', JSON.stringify(transactions));
  }, [transactions]);

  if (authLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Initializing DukaanMitra...</p>
      </div>
    );
  }

  // Auth Gate: If user tries to access protected views without being logged in
  const isProtectedView = activeView !== 'landing';
  if (isProtectedView && !user) {
    return <Auth onSuccess={() => setActiveView('dashboard')} />;
  }

  const renderView = () => {
    switch (activeView) {
      case 'landing':
        return <LandingPage setView={setActiveView} />;
      case 'superadmin':
        return <SuperAdmin customers={customers} transactions={transactions} logs={logs} />;
      case 'shop_panel':
        return (
          <ShopPanel 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'dashboard':
        return <Dashboard customers={customers} transactions={transactions} />;
      case 'sheets_db':
        return <SheetsDatabase customers={customers} transactions={transactions} />;
      case 'architecture':
        return <ArchitectureGuide />;
      case 'build':
        return <BuildGuide />;
      case 'optimization':
        return <OptimizationPlaybook />;
      case 'recovery':
        return <RecoveryOps />;
      case 'assets':
        return <AssetLibrary />;
      case 'sales':
        return <StreetSalesPlaybook />;
      case 'founder':
        return <FounderOperations customers={customers} />;
      case 'platform':
        return <PlatformSaaS />;
      case 'scaling':
        return <ScalingPlaybook />;
      case 'customers':
        return <CustomerList customers={customers} transactions={transactions} />;
      case 'transactions':
        return <TransactionList transactions={transactions} />;
      case 'deployment':
        return <DeploymentGuide />;
      case 'operations':
        return <OperationsPlaybook />;
      case 'reliability':
        return <ReliabilityPlaybook />;
      case 'simulator':
        return (
          <Simulator 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'logs':
        return <SystemLogs logs={logs} />;
      default:
        return <Dashboard customers={customers} transactions={transactions} />;
    }
  };

  return (
    <Layout activeView={activeView} setView={setActiveView}>
      {renderView()}
      {activeView !== 'landing' && <ChatBot />}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword,
  sendEmailVerification,
  signOut 
} from 'firebase/auth';
import { auth } from '../firebase';

interface AuthProps {
  onSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onSuccess }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [showVerification, setShowVerification] = useState(false);
  const [verificationEmail, setVerificationEmail] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isSignUp) {
        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        await sendEmailVerification(userCredential.user);
        // Do not sign them in automatically as per requirement
        await signOut(auth);
        setVerificationEmail(email);
        setShowVerification(true);
      } else {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        if (!userCredential.user.emailVerified) {
          setVerificationEmail(userCredential.user.email || email);
          await signOut(auth);
          setShowVerification(true);
        } else {
          onSuccess();
        }
      }
    } catch (err: any) {
      console.error("Auth error:", err.code);
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password' || err.code === 'auth/user-not-found') {
        setError("Email or password is incorrect");
      } else if (err.code === 'auth/email-already-in-use') {
        setError("User already exists. Please sign in");
      } else {
        setError("An error occurred. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  if (showVerification) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 via-white to-emerald-50 px-6">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-10 border border-slate-100 animate-in fade-in zoom-in duration-500 text-center space-y-8">
          <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center text-3xl mx-auto text-indigo-600 animate-pulse">
            ✉️
          </div>
          <div className="space-y-4">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight italic">Verify Your Email</h2>
            <p className="text-slate-500 font-medium leading-relaxed">
              We have sent you a verification email to <span className="text-indigo-600 font-bold">{verificationEmail}</span>. Please verify it and log in.
            </p>
          </div>
          <button
            onClick={() => {
              setShowVerification(false);
              setError(null);
              setIsSignUp(false); // Switch to login mode
            }}
            className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-slate-200 hover:bg-black transition active:scale-95"
          >
            Return to Login ➔
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 via-white to-emerald-50 px-6">
      <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-10 border border-slate-100 animate-in fade-in zoom-in duration-500">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-black italic tracking-tighter text-indigo-600 mb-2">DukaanMitra</h1>
          <p className="text-slate-500 font-bold text-sm uppercase tracking-widest">
            {isSignUp ? 'Create your platform account' : 'Sign in to your ledger'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Email Address</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
              placeholder="name@example.com"
