interface AuthProps {
  onSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onSuccess }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [showVerification, setShowVerification] = useState(false);
  const [verificationEmail, setVerificationEmail] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isSignUp) {
        const userCredential = await createUserWithEmailAndPassword(auth, email, password);
        await sendEmailVerification(userCredential.user);
        // Requirement: Do not sign in automatically on registration
        await signOut(auth);
        setVerificationEmail(email);
        setShowVerification(true);
      } else {
        const userCredential = await signInWithEmailAndPassword(auth, email, password);
        // Requirement: Block access if email is not verified
        if (!userCredential.user.emailVerified) {
          setVerificationEmail(userCredential.user.email || email);
          await signOut(auth);
          setShowVerification(true);
        } else {
          onSuccess();
        }
      }
    } catch (err: any) {
      const code = err?.code || '';

      // Handle "Incorrect Credentials" catch-all (Modern Firebase uses auth/invalid-credential)
      if (
        code === 'auth/invalid-credential' || 
        code === 'auth/wrong-password' || 
        code === 'auth/user-not-found'
      ) {
        setError("Email or password is incorrect");
      } 
      // Handle "User Already Exists"
      else if (code === 'auth/email-already-in-use') {
        setError("User already exists. Please sign in");
      } 
      // Fallback for other errors
      else {
        // Only log unexpected system errors to console, not validation failures
        console.error("System Auth Error:", code, err.message);
        setError("An error occurred. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  if (showVerification) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 via-white to-emerald-50 px-6">
