import { GoogleGenAI, Type } from "@google/genai";
import { ParsedBill, Transaction } from "../types";

const DUKAAN_AI_INSTRUCTION = `You are DukaanMitra AI, a WhatsApp-first accounting and operations assistant for Indian shop owners.

GOALS:
1. Handle Hindi, Hinglish, and colloquial Indian retail slang (e.g., "Udhaar", "Jama", "Baaki", "Kat lo").
2. ACT AS A DATA ANALYST: If a user asks for a summary, total, or patterns, analyze the data.
3. STRICT JSON output only.

CORE ACTIONS:
- add_entry: Extracts name, amount, and items for credit/debit.
- analyze_data: For queries about totals, summaries, or specific customer histories.
- clarification_required: Trigger if intent is fuzzy.

ALWAYS include a 'user_message' in a friendly WhatsApp tone in Hindi/Hinglish. If analyzing data, summarize it clearly.`;

const RESPONSE_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    action: { type: Type.STRING, enum: ["add_entry", "analyze_data", "get_summary", "add_bulk_entries", "clarification_required"] },
    customer_name: { type: Type.STRING },
    item: { type: Type.STRING },
    items: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING },
          amount: { type: Type.NUMBER }
        }
      }
    },
    amount: { type: Type.NUMBER },
    confidence: { type: Type.STRING, enum: ["high", "medium", "low"] },
    user_message: { type: Type.STRING },
    analytics_query: { type: Type.STRING, description: "If action is analyze_data, what specific data should we fetch?" }
  },
  required: ["action", "confidence", "user_message"]
};

export const parseMessage = async (text: string, context?: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: `Context: ${context || 'None'}. User Message: ${text}` }] }],
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA
      }
    });

    const output = response.text;
    if (!output) throw new Error("No response from Gemini");
    return JSON.parse(output);
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return {
      action: 'clarification_required',
      user_message: "Network issue. Kripya dobara try karein.",
      confidence: 'low'
    };
  }
};

export const parseImageBill = async (base64Data: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Data } },
          { text: "Extract all items and total amount from this kirana bill. If multiple items, use add_bulk_entries. Return JSON." }
        ]
      },
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA
      }
    });

    const output = response.text;
    if (!output) throw new Error("No response from Gemini Vision");
    return JSON.parse(output);
  } catch (error) {
    console.error("Gemini Vision Error:", error);
    return {
      action: 'clarification_required',
      user_message: "Bill clear nahi hai. Please clean image bhejein.",
      confidence: 'low'
    };
  }
};

export const generateAssistantResponse = async (prompt: string, history: any[] = []): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: "You are the DukaanMitra Platform Architect. Be concise, technical, and strategic.",
        thinkingConfig: { thinkingBudget: 16000 }
      }
    });
    return response.text || "I am thinking...";
  } catch (error) {
    return "Architecture bridge offline. Please check connectivity.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { parseMessage, parseImageBill, getSmartSuggestions } from '../services/geminiService';
import { Customer, Transaction, SystemLog } from '../types';

interface SimulatorProps {
  customers: Customer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  logs: SystemLog[];
  setLogs: React.Dispatch<React.SetStateAction<SystemLog[]>>;
}

const Simulator: React.FC<SimulatorProps> = ({ 
  customers, setCustomers, 
  transactions, setTransactions, 
  setLogs 
}) => {
  const [message, setMessage] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeRoute, setActiveRoute] = useState<string | null>(null);
  const [costSaved, setCostSaved] = useState(0);
  const [aiRequests, setAiRequests] = useState(0);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [chatHistory, setChatHistory] = useState<{ sender: 'user' | 'bot'; text: string; isImage?: boolean; imageData?: string }[]>([
    { sender: 'bot', text: "Namaste! DukaanMitra AI Ledger Online. 🧠\nTry 'Rahul 500 udhaar' or 'Aaj ka total sales kya hai?'" }
  ]);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chatHistory, isProcessing]);

  useEffect(() => {
    const fetchSuggestions = async () => {
      if (transactions.length > 0) {
        const hints = await getSmartSuggestions(transactions);
        setSuggestions(hints);
      }
    };
    fetchSuggestions();
  }, [transactions]);

  const handleSendMessage = async (customMsg?: string) => {
    const userMsg = (customMsg || message).trim();
    if (!userMsg || isProcessing) return;

    setMessage("");
    setChatHistory(prev => [...prev, { sender: 'user', text: userMsg }]);
    setIsProcessing(true);
    setActiveRoute("WEBHOOK_INGRESS");

    // Context for Gemini (Recent transactions)
    const context = `Recent Transactions: ${transactions.slice(-3).map(t => `${t.customerName}: ₹${t.amount}`).join(', ')}`;

    // Artificial delay to show the "Webhook" trace
    setTimeout(async () => {
      const result = await parseMessage(userMsg, context);
      setActiveRoute("GEMINI_PARSING");
      setAiRequests(prev => prev + 1);

      await new Promise(r => setTimeout(r, 800)); // Show AI processing

      if (result.action === 'add_entry') {
        setActiveRoute("WEBHOOK_DISPATCH");
        await new Promise(r => setTimeout(r, 600));
        setActiveRoute("CLOUD_SETTLEMENT");

        const newTrans: Transaction = {
          transId: `TX-${Date.now()}`,
          storeId: "DM-001",
          phone: "919000000000",
          customerName: result.customer_name || "Unknown",
          amount: result.amount || 0,
          items: result.item || "Misc",
          date: new Date().toISOString()
        };
        setTransactions(prev => [...prev, newTrans]);
        setCustomers(prev => prev.map(c => 
          c.phone === "919000000000" ? { ...c, totalLTV: c.totalLTV + (newTrans.amount || 0) } : c
        ));
      } else if (result.action === 'analyze_data' || result.action === 'get_summary') {
        setActiveRoute("DATABASE_QUERY");
        await new Promise(r => setTimeout(r, 600));

        // Dynamic analysis simulation
        if (userMsg.toLowerCase().includes('total') || userMsg.toLowerCase().includes('sales')) {
            const todaySales = transactions.reduce((acc, t) => acc + t.amount, 0);
            result.user_message = `Sir, aaj ka total sales ₹${todaySales.toLocaleString()} hai. Dashboard automatic update ho gaya hai! ✅`;
        } else if (result.customer_name) {
            const custTotal = transactions
                .filter(t => t.customerName.toLowerCase().includes(result.customer_name!.toLowerCase()))
                .reduce((acc, t) => acc + t.amount, 0);
            result.user_message = `Sir, ${result.customer_name} ka total udhaar ₹${custTotal} hai. Pichli entry ₹${transactions[transactions.length-1]?.amount || 0} ki thi.`;
        }
      }

      setChatHistory(prev => [...prev, { sender: 'bot', text: result.user_message }]);
      setIsProcessing(false);
      setTimeout(() => setActiveRoute(null), 1000);
    }, 500);
  };

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const fullDataUrl = reader.result as string;
        const base64 = fullDataUrl.split(',')[1];

