export const getNearbyLogistics = async (lat: number, lng: number): Promise<{ text: string, links: { uri: string, title: string }[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Find 3 nearby wholesale suppliers or logistics services for kirana stores near latitude ${lat}, longitude ${lng} in India.`,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || "Search failed.";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = groundingChunks
      .filter((c: any) => c.web)
      .map((c: any) => ({
        uri: c.web.uri,
        title: c.web.title || "External Source"
      }));

    return { text, links };
  } catch (error) {
    console.error("Logistics Search Error:", error);
    return { text: "Failed to search for logistics.", links: [] };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { parseMessage, parseImageBill, getSmartSuggestions } from '../services/geminiService';
import { Customer, Transaction, SystemLog } from '../types';

interface SimulatorProps {
  customers: Customer[];
  setCustomers: React.Dispatch<React.SetStateAction<Customer[]>>;
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
  logs: SystemLog[];
  setLogs: React.Dispatch<React.SetStateAction<SystemLog[]>>;
}

const Simulator: React.FC<SimulatorProps> = ({ 
  customers, setCustomers, 
  transactions, setTransactions, 
  setLogs 
}) => {
  const [message, setMessage] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeRoute, setActiveRoute] = useState<string | null>(null);
  const [simulatedTime, setSimulatedTime] = useState(new Date());
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [chatHistory, setChatHistory] = useState<{ sender: 'user' | 'bot'; text: string; isImage?: boolean; imageData?: string; timestamp: string }[]>([
    { sender: 'bot', text: "Namaste! DukaanMitra AI Ledger Online. 🧠\nTry 'Rahul 500 udhaar' or 'Aaj ka total sales kya hai?'", timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }
  ]);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Update clock every minute
  useEffect(() => {
    const timer = setInterval(() => {
      setSimulatedTime(prev => new Date(prev.getTime() + 60000));
    }, 60000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chatHistory, isProcessing]);

  useEffect(() => {
    const fetchSuggestions = async () => {
      if (transactions.length > 0) {
        const hints = await getSmartSuggestions(transactions);
        setSuggestions(hints);
      }
    };
    fetchSuggestions();
  }, [transactions]);

  const handleSendMessage = async (customMsg?: string) => {
    const userMsg = (customMsg || message).trim();
    if (!userMsg || isProcessing) return;

    setMessage("");
    const nowStr = simulatedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    setChatHistory(prev => [...prev, { sender: 'user', text: userMsg, timestamp: nowStr }]);
    setIsProcessing(true);
    setActiveRoute("WEBHOOK_INGRESS");

    // Context for Gemini includes the simulated time and relevant history
    const context = `
      Simulated Current Time: ${simulatedTime.toLocaleString('en-IN')}
      Database State:
      Total Transactions: ${transactions.length}
      Recent Transactions: ${transactions.slice(-10).map(t => `[${new Date(t.date).toLocaleDateString()}] ${t.customerName}: ₹${t.amount} (${t.items})`).join('; ')}
    `;

    setTimeout(async () => {
      const result = await parseMessage(userMsg, context);
      setActiveRoute("GEMINI_PARSING");

      await new Promise(r => setTimeout(r, 800));

      if (result.action === 'add_entry') {
        setActiveRoute("WEBHOOK_DISPATCH");
        await new Promise(r => setTimeout(r, 600));
        setActiveRoute("CLOUD_SETTLEMENT");

        const newTrans: Transaction = {
          transId: `TX-${Date.now()}`,
          storeId: "DM-001",
          phone: "919000000000",
          customerName: result.customer_name || "Unknown",
          amount: result.amount || 0,
          items: result.item || "Misc",
          date: simulatedTime.toISOString()
        };
        setTransactions(prev => [...prev, newTrans]);
        setCustomers(prev => prev.map(c => 
          c.phone === "919000000000" ? { ...c, totalLTV: c.totalLTV + (newTrans.amount || 0) } : c
        ));
      } else if (result.action === 'analyze_data' || result.action === 'get_summary') {
        setActiveRoute("DATABASE_QUERY");
        await new Promise(r => setTimeout(r, 600));

        // Use simulation logic for queries
        const lowerMsg = userMsg.toLowerCase();
        if (lowerMsg.includes('kal') || lowerMsg.includes('yesterday')) {
          const yesterday = new Date(simulatedTime);
          yesterday.setDate(yesterday.getDate() - 1);
          const yesterdayStr = yesterday.toLocaleDateString();
          const yesterdaySales = transactions
            .filter(t => new Date(t.date).toLocaleDateString() === yesterdayStr)
            .reduce((acc, t) => acc + t.amount, 0);
          result.user_message = `Sir, kal (${yesterdayStr}) ki total sales ₹${yesterdaySales.toLocaleString()} thi. Check my report! 📊`;
        } else if (lowerMsg.includes('aaj') || lowerMsg.includes('today') || lowerMsg.includes('sales')) {
          const todayStr = simulatedTime.toLocaleDateString();
          const todaySales = transactions
            .filter(t => new Date(t.date).toLocaleDateString() === todayStr)
            .reduce((acc, t) => acc + t.amount, 0);
          result.user_message = `Sir, aaj ka total sales ₹${todaySales.toLocaleString()} hai. Dashboard live hai! ✅`;
        }
      }

      setChatHistory(prev => [...prev, { sender: 'bot', text: result.user_message, timestamp: simulatedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }]);
      setIsProcessing(false);
      setTimeout(() => setActiveRoute(null), 1000);
    }, 500);
  };

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = async () => {
        const fullDataUrl = reader.result as string;
        const base64 = fullDataUrl.split(',')[1];

        setChatHistory(prev => [...prev, { sender: 'user', text: "Analyzing bill photo...", isImage: true, imageData: fullDataUrl, timestamp: simulatedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }]);
        setIsProcessing(true);
        setActiveRoute("VISION_ENGINE");

        const result = await parseImageBill(base64);

        if (result.action === 'add_bulk_entries' && result.items) {
          setActiveRoute("WEBHOOK_DISPATCH");
          await new Promise(r => setTimeout(r, 800));
          setActiveRoute("CLOUD_SETTLEMENT");

          const bulk = result.items.map((it, i) => ({
            transId: `TX-V-${Date.now()}-${i}`,
            storeId: "DM-001",
            phone: "919000000000",
            customerName: result.customer_name || "Vision Customer",
            amount: it.amount,
            items: it.item,
            date: simulatedTime.toISOString()
          }));
          setTransactions(prev => [...prev, ...bulk]);
        }

        setChatHistory(prev => [...prev, { sender: 'bot', text: result.user_message, timestamp: simulatedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }]);
        setIsProcessing(false);
        setTimeout(() => setActiveRoute(null), 1000);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-160px)]">
      {/* WhatsApp Device Simulator */}
      <div className="lg:w-[400px] mx-auto bg-slate-900 p-3 rounded-[3rem] shadow-2xl flex flex-col relative border-[8px] border-slate-800">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-40 h-6 bg-slate-800 rounded-b-2xl z-10 flex items-center justify-center">
            <div className="w-1.5 h-1.5 bg-slate-700 rounded-full"></div>
        </div>

        <div className="flex-1 bg-[#efe7de] rounded-[2.5rem] overflow-hidden flex flex-col relative">
          {/* WA Header */}
          <div className="bg-indigo-700 p-4 pt-8 text-white flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 bg-indigo-500 rounded-full flex items-center justify-center font-bold shadow-inner">DM</div>
              <div>
                <p className="font-bold text-sm">DukaanMitra AI</p>
                <p className="text-[9px] opacity-70 flex items-center gap-1">
                  <span className="w-1 h-1 bg-emerald-400 rounded-full animate-pulse"></span>
                  Online • {simulatedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
            </div>
            <div className="text-right flex flex-col items-end">
              <input 
                type="date" 
                className="bg-transparent border-none text-[8px] font-bold text-indigo-200 focus:outline-none cursor-pointer hover:text-white transition-colors"
                value={simulatedTime.toISOString().split('T')[0]}
                onChange={(e) => {
                    const newDate = new Date(e.target.value);
                    newDate.setHours(simulatedTime.getHours(), simulatedTime.getMinutes());
                    setSimulatedTime(newDate);
                }}
              />
              <p className="text-[10px] font-black text-emerald-400 tracking-tighter">SIMULATED</p>
            </div>
          </div>

          {/* Chat Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar">
            {chatHistory.map((chat, i) => (
              <div key={i} className={`flex ${chat.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm shadow-sm relative ${
                  chat.sender === 'user' ? 'bg-[#dcf8c6] rounded-tr-none' : 'bg-white rounded-tl-none border-l-4 border-l-indigo-500'
                }`}>
                  {chat.isImage && <img src={chat.imageData} className="rounded-lg mb-2 max-h-48 w-full object-cover" />}
                  <p className="whitespace-pre-wrap leading-relaxed">{chat.text}</p>
                  <div className="flex items-center justify-end space-x-1 mt-1 opacity-50">
                    <span className="text-[8px]">{chat.timestamp}</span>
                    <span className="text-[8px] text-blue-500">✓✓</span>
                  </div>
                </div>
              </div>
            ))}
            {isProcessing && (
              <div className="flex justify-start">
                <div className="bg-white/80 backdrop-blur-sm p-2 px-4 rounded-xl flex items-center space-x-2">
                  <div className="flex space-x-1">
                    <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce delay-75"></div>
                    <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce delay-150"></div>
                  </div>
                  <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">AI Thinking...</span>
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input Area */}
          <div className="p-3 bg-white border-t space-y-2">
            <div className="flex items-center space-x-2 overflow-x-auto no-scrollbar py-1">
              {suggestions.map((s, i) => (
                <button key={i} onClick={() => handleSendMessage(s)} className="shrink-0 px-3 py-1 bg-slate-100 rounded-full text-[10px] font-bold text-slate-600 border border-slate-200 hover:bg-indigo-50 transition whitespace-nowrap">
                  {s}
                </button>
              ))}
            </div>
            <div className="flex items-center space-x-2">
              <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
              <button onClick={() => fileInputRef.current?.click()} className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center hover:bg-slate-200 transition text-lg">📷</button>
              <input 
                value={message}
                onChange={e => setMessage(e.target.value)}
                onKeyPress={e => e.key === 'Enter' && handleSendMessage()}
                placeholder="Message DukaanMitra..."
                className="flex-1 bg-slate-100 rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-indigo-300 transition-all"
              />
              <button onClick={() => handleSendMessage()} className="w-10 h-10 rounded-full bg-indigo-600 text-white flex items-center justify-center shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition active:scale-90">➔</button>
            </div>
          </div>
        </div>
      </div>

      {/* Backend Orchestrator Tracing Panel */}
      <div className="flex-1 space-y-6 hidden lg:block">
        <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm h-full flex flex-col">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-xl font-black text-slate-900 flex items-center gap-2 italic uppercase">
              <span className="text-indigo-600">⚡</span> WhatsApp Webhook Trace
            </h3>
            <div className="flex items-center gap-4">
                <div className="text-right">
                    <p className="text-[9px] font-black text-slate-400 uppercase">Context Date</p>
