import React, { useState } from 'react';
import { auth } from '../firebase';

interface AuthProps {
  onSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onSuccess }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [showVerification, setShowVerification] = useState(false);
  const [verificationEmail, setVerificationEmail] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isSignUp) {
        // Using auth methods on the instance for better compatibility
        const userCredential = await auth.createUserWithEmailAndPassword(email, password);
        await userCredential.user?.sendEmailVerification();
        // Requirement: Do not sign in automatically on registration
        await auth.signOut();
        setVerificationEmail(email);
        setShowVerification(true);
      } else {
        const userCredential = await auth.signInWithEmailAndPassword(email, password);
        // Requirement: Block access if email is not verified
        if (!userCredential.user?.emailVerified) {
          setVerificationEmail(userCredential.user?.email || email);
          await auth.signOut();
          setShowVerification(true);
        } else {
          onSuccess();
        }
      }
    } catch (err: any) {
      const code = err?.code || '';

      // Handle "Incorrect Credentials" catch-all (Modern Firebase uses auth/invalid-credential)
      if (
        code === 'auth/invalid-credential' || 
        code === 'auth/wrong-password' || 
        code === 'auth/user-not-found'
      ) {
        setError("Email or password is incorrect");
      } 
      // Handle "User Already Exists"
      else if (code === 'auth/email-already-in-use') {
        setError("User already exists. Please sign in");
      } 
      // Fallback for other errors
      else {
        // Only log unexpected system errors to console, not validation failures
        console.error("System Auth Error:", code, err.message);
        setError("An error occurred. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  if (showVerification) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 via-white to-emerald-50 px-6">
        <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-10 border border-slate-100 animate-in fade-in zoom-in duration-500 text-center space-y-8">
          <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center text-3xl mx-auto text-indigo-600 animate-pulse">
            ✉️
          </div>
          <div className="space-y-4">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight italic">Verify Your Email</h2>
            <p className="text-slate-500 font-medium leading-relaxed">
              We have sent you a verification email to <span className="text-indigo-600 font-bold">{verificationEmail}</span>. Please verify it and log in.
            </p>
          </div>
          <button
            onClick={() => {
              setShowVerification(false);
              setError(null);
              setIsSignUp(false); // Switch to login mode for the verified user
            }}
            className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-slate-200 hover:bg-black transition active:scale-95"
          >
            Return to Login ➔
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 via-white to-emerald-50 px-6">
      <div className="w-full max-w-md bg-white rounded-[3rem] shadow-2xl p-10 border border-slate-100 animate-in fade-in zoom-in duration-500">
        <div className="text-center mb-10">
          <h1 className="text-4xl font-black italic tracking-tighter text-indigo-600 mb-2">DukaanMitra</h1>
          <p className="text-slate-500 font-bold text-sm uppercase tracking-widest">
            {isSignUp ? 'Create your platform account' : 'Sign in to your ledger'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Email Address</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
              placeholder="name@example.com"
            />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-2">Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 font-medium focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
              placeholder="••••••••"
            />
          </div>

          {error && (
            <div className="bg-rose-50 border border-rose-100 text-rose-600 px-4 py-3 rounded-2xl text-xs font-bold text-center animate-shake">
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black text-lg shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition active:scale-95 disabled:opacity-50"
          >
            {loading ? 'Processing...' : (isSignUp ? 'Join DukaanMitra ➔' : 'Enter Dashboard ➔')}
          </button>
        </form>

        <div className="mt-8 text-center">
          <button
            onClick={() => {
              setIsSignUp(!isSignUp);
              setError(null);
            }}
            className="text-slate-400 text-sm font-bold hover:text-indigo-600 transition"
          >
            {isSignUp ? 'Already have an account? Sign In' : 'New here? Create an Account'}
          </button>
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-5px); }
          75% { transform: translateX(5px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 0s 2;
        }
      `}</style>
    </div>
  );
};

