  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isForgotPassword) {
        await auth.sendPasswordResetEmail(email);
        setResetSent(true);
      } else if (isSignUp) {
        // Using auth methods on the instance for better compatibility
        const userCredential = await auth.createUserWithEmailAndPassword(email, password);
        await userCredential.user?.sendEmailVerification();
        // Requirement: Do not sign in automatically on registration
        await auth.signOut();
        setVerificationEmail(email);
        setShowVerification(true);
      } else {
        const userCredential = await auth.signInWithEmailAndPassword(email, password);
        // Requirement: Block access if email is not verified
        if (!userCredential.user?.emailVerified) {
          setVerificationEmail(userCredential.user?.email || email);
          await auth.signOut();
          setShowVerification(true);
        } else {
          onSuccess();
        }
      }
    } catch (err: any) {
      const code = err?.code || '';

      // Handle specific Auth errors
      if (
        code === 'auth/invalid-credential' || 
        code === 'auth/wrong-password' || 
        code === 'auth/user-not-found'
      ) {
        setError(isForgotPassword ? "No account found with this email" : "Email or password is incorrect");
      } 
      else if (code === 'auth/email-already-in-use') {
        setError("User already exists. Please sign in");
      } 
      else if (code === 'auth/too-many-requests') {
        setError("Too many attempts. Please try again later");
      }
      else {
        console.error("System Auth Error:", code, err.message);
        setError("An error occurred. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  if (showVerification) {
