interface AuthProps {
  onSuccess: () => void;
}

const Auth: React.FC<AuthProps> = ({ onSuccess }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [isForgotPassword, setIsForgotPassword] = useState(false);
  const [showVerification, setShowVerification] = useState(false);
  const [resetSent, setResetSent] = useState(false);
  const [verificationEmail, setVerificationEmail] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isForgotPassword) {
        if (!email.trim()) {
          setError("Please enter your email address");
          setLoading(false);
          return;
        }
        await auth.sendPasswordResetEmail(email);
        setResetSent(true);
      } else if (isSignUp) {
        const userCredential = await auth.createUserWithEmailAndPassword(email, password);
        await userCredential.user?.sendEmailVerification();
        await auth.signOut();
        setVerificationEmail(email);
        setShowVerification(true);
      } else {
        const userCredential = await auth.signInWithEmailAndPassword(email, password);
        if (!userCredential.user?.emailVerified) {
          setVerificationEmail(userCredential.user?.email || email);
          await auth.signOut();
          setShowVerification(true);
        } else {
          onSuccess();
        }
      }
    } catch (err: any) {
      const code = err?.code || '';
      if (code === 'auth/invalid-credential' || code === 'auth/wrong-password' || code === 'auth/user-not-found') {
        setError(isForgotPassword ? "No account found with this email" : "Email or password is incorrect");
      } else if (code === 'auth/email-already-in-use') {
        setError("User already exists. Please sign in");
      } else if (code === 'auth/too-many-requests') {
        setError("Too many attempts. Please try again later");
      } else {
        console.error("System Auth Error:", code, err.message);
        setError("An error occurred. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  if (showVerification) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-50 via-white to-emerald-50 px-6">
