import Dashboard from './components/Dashboard';
import CustomerList from './components/CustomerList';
import TransactionList from './components/TransactionList';
import Simulator from './components/Simulator';
import ShopPanel from './components/ShopPanel';
import SuperAdmin from './components/SuperAdmin';
import SystemLogs from './components/SystemLogs';
import DeploymentGuide from './components/DeploymentGuide';
import OperationsPlaybook from './components/OperationsPlaybook';
import ReliabilityPlaybook from './components/ReliabilityPlaybook';
import ScalingPlaybook from './components/ScalingPlaybook';
import PlatformSaaS from './components/PlatformSaaS';
import FounderOperations from './components/FounderOperations';
import StreetSalesPlaybook from './components/StreetSalesPlaybook';
import AssetLibrary from './components/AssetLibrary';
import BuildGuide from './components/BuildGuide';
import RecoveryOps from './components/RecoveryOps';
import OptimizationPlaybook from './components/OptimizationPlaybook';
import ArchitectureGuide from './components/ArchitectureGuide';
import SheetsDatabase from './components/SheetsDatabase';
import TrainingCenter from './components/TrainingCenter';
import ChatBot from './components/ChatBot';
import Auth from './components/Auth';
import { INITIAL_CUSTOMERS, INITIAL_TRANSACTIONS, INITIAL_LOGS } from './constants';
import { Customer, Transaction, SystemLog, View } from './types';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>('landing');
  // Use any for user type as User named export is not found
  const [user, setUser] = useState<any | null>(null);
  const [authLoading, setAuthLoading] = useState(true);

  // Persistence Loading
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('dm_customers');
    return saved ? JSON.parse(saved) : INITIAL_CUSTOMERS;
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('dm_transactions');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [logs, setLogs] = useState<SystemLog[]>(INITIAL_LOGS);

  // Auth Listener - Using compat style methods on the auth instance
  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged(async (currentUser) => {
      // If user exists but is not verified, force sign out to trigger Auth screen gate
      if (currentUser && !currentUser.emailVerified) {
        await auth.signOut();
        setUser(null);
      } else {
        setUser(currentUser);
      }

      setAuthLoading(false);

      // If user logs in and we are on landing, redirect to dashboard
      if (currentUser && currentUser.emailVerified && activeView === 'landing') {
        setActiveView('dashboard');
      }
    });
    return () => unsubscribe();
  }, [activeView]);

  // Persistence Saving
  useEffect(() => {
    localStorage.setItem('dm_customers', JSON.stringify(customers));
  }, [customers]);

  useEffect(() => {
    localStorage.setItem('dm_transactions', JSON.stringify(transactions));
  }, [transactions]);

  if (authLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Initializing DukaanMitra...</p>
      </div>
    );
  }

  // Auth Gate: If user tries to access protected views without being logged in (or if unverified, user is null)
  const isProtectedView = activeView !== 'landing';
  if (isProtectedView && !user) {
    return <Auth onSuccess={() => setActiveView('dashboard')} />;
  }

  const renderView = () => {
    switch (activeView) {
      case 'landing':
        return <LandingPage setView={setActiveView} />;
      case 'superadmin':
        return <SuperAdmin customers={customers} transactions={transactions} logs={logs} />;
      case 'shop_panel':
        return (
          <ShopPanel 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'dashboard':
        return <Dashboard customers={customers} transactions={transactions} />;
      case 'sheets_db':
        return <SheetsDatabase customers={customers} transactions={transactions} />;
      case 'architecture':
        return <ArchitectureGuide />;
      case 'build':
        return <BuildGuide />;
      case 'optimization':
        return <OptimizationPlaybook />;
      case 'recovery':
        return <RecoveryOps />;
      case 'assets':
        return <AssetLibrary />;
      case 'sales':
        return <StreetSalesPlaybook />;
      case 'founder':
        return <FounderOperations customers={customers} />;
      case 'platform':
        return <PlatformSaaS />;
      case 'scaling':
        return <ScalingPlaybook />;
      case 'customers':
        return <CustomerList customers={customers} transactions={transactions} />;
      case 'transactions':
        return <TransactionList transactions={transactions} />;
      case 'deployment':
        return <DeploymentGuide />;
      case 'operations':
        return <OperationsPlaybook />;
      case 'reliability':
        return <ReliabilityPlaybook />;
      case 'training':
        return <TrainingCenter />;
      case 'simulator':
        return (
          <Simulator 
            customers={customers} 
            setCustomers={setCustomers}
            transactions={transactions}
            setTransactions={setTransactions}
            logs={logs}
            setLogs={setLogs}
          />
        );
      case 'logs':
        return <SystemLogs logs={logs} />;
      default:
        return <Dashboard customers={customers} transactions={transactions} />;
    }
  };

  return (
    <Layout activeView={activeView} setView={setActiveView}>
      {renderView()}
      {activeView !== 'landing' && <ChatBot />}
    </Layout>
  );
};

