import { GoogleGenAI, Type } from "@google/genai";
import { ParsedBill, Transaction, BlogPost } from "../types";

const DUKAAN_AI_INSTRUCTION = `You are DukaanMitra AI, a WhatsApp-first accounting and operations assistant for Indian shop owners.

TEMPORAL AWARENESS:
- You will be provided with a "Simulated Current Time". Use this as the reference for "today".
- Resolve relative terms like "kal" (yesterday), "aaj" (today), "pichle hafte" (last week) based on this timestamp.

GOALS:
1. Handle Hindi, Hinglish, and colloquial Indian retail slang (e.g., "Udhaar", "Jama", "Baaki", "Kat lo").
2. ACT AS A DATA ANALYST: If a user asks for a summary, total, or patterns, analyze the data provided in context.
3. STRICT JSON output only.

CORE ACTIONS:
- add_entry: Extracts name, amount, and items for credit/debit.
- analyze_data: For queries about totals, summaries, or specific customer histories.
- clarification_required: Trigger if intent is fuzzy.

ALWAYS include a 'user_message' in a friendly WhatsApp tone in Hindi/Hinglish. If analyzing data, summarize it clearly.`;

const RESPONSE_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    action: { type: Type.STRING, enum: ["add_entry", "analyze_data", "get_summary", "add_bulk_entries", "clarification_required"] },
    customer_name: { type: Type.STRING },
    item: { type: Type.STRING },
    items: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          item: { type: Type.STRING },
          amount: { type: Type.NUMBER }
        }
      }
    },
    amount: { type: Type.NUMBER },
    confidence: { type: Type.STRING, enum: ["high", "medium", "low"] },
    user_message: { type: Type.STRING },
    analytics_query: { type: Type.STRING, description: "If action is analyze_data, what specific data should we fetch?" }
  },
  required: ["action", "confidence", "user_message"]
};

export const parseMessage = async (text: string, context?: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: `Simulated System Time: ${new Date().toLocaleString('en-IN')}\nContext: ${context || 'None'}\nUser Message: ${text}` }] }],
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA
      }
    });

    const output = response.text;
    if (!output) throw new Error("No response from Gemini");
    return JSON.parse(output);
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return {
      action: 'clarification_required',
      user_message: "Network issue. Kripya dobara try karein.",
      confidence: 'low'
    };
  }
};

export const parseImageBill = async (base64Data: string): Promise<ParsedBill> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: {
        parts: [
          { inlineData: { mimeType: "image/jpeg", data: base64Data } },
          { text: `Current Time: ${new Date().toLocaleString()}\nExtract all items and total amount from this kirana bill. If multiple items, use add_bulk_entries. Return JSON.` }
        ]
      },
      config: {
        systemInstruction: DUKAAN_AI_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: RESPONSE_SCHEMA
      }
    });

    const output = response.text;
    if (!output) throw new Error("No response from Gemini Vision");
    return JSON.parse(output);
  } catch (error) {
    console.error("Gemini Vision Error:", error);
    return {
      action: 'clarification_required',
      user_message: "Bill clear nahi hai. Please clean image bhejein.",
      confidence: 'low'
    };
  }
};

export const generateAssistantResponse = async (prompt: string, history: any[] = []): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: "You are the DukaanMitra Platform Architect. Be concise, technical, and strategic.",
        thinkingConfig: { thinkingBudget: 16000 }
      }
    });
    return response.text || "I am thinking...";
  } catch (error) {
    return "Architecture bridge offline. Please check connectivity.";
  }
};

export const getSmartSuggestions = async (transactions: Transaction[]): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Current Date: ${new Date().toDateString()}. Based on these transactions: ${JSON.stringify(transactions.slice(-3))}, suggest 3 short Hinglish WhatsApp messages a shop owner would send to record a bill. Return as a JSON array of strings.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch {
    return ["Rahul 500 udhaar", "Aaj ka total sales?", "Aman 100 jama"];
