      TONE: Professional but in a Hinglish/English mix that feels local.
      Return as a JSON array of objects with keys: id, title, excerpt, content, tag, date (use 2025-12-XX).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              title: { type: Type.STRING },
              excerpt: { type: Type.STRING },
              content: { type: Type.STRING },
              tag: { type: Type.STRING },
              date: { type: Type.STRING }
            },
            required: ["id", "title", "excerpt", "content", "tag", "date"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Blog Generation Error:", error);
    return [];
  }
};

